{
  "acts": [
    {
      "number": 1,
      "name": "The Anomaly Arrives",
      "summary": "Maret lives quietly as a scribe, hiding her true power behind fake stats. When Arbiter Cassel arrives to investigate her anomaly, she tries to deflect by using her administrative access to appear normal. Theo inadvertently helps her by vouching for her, but Cassel's scrutiny forces Maret to use her real strength to save Theo from a collapsing shelf—an act that Cassel witnesses.",
      "emotionalArc": "fear and routine shattered by suspicion, building to desperation",
      "turningPoint": "Maret bends an iron shelf to save Theo, and Cassel sees her Strength of at least 20, confirming the anomaly."
    },
    {
      "number": 2,
      "name": "The System's Trial",
      "summary": "Maret attempts to evade Cassel by altering records and faking a quest failure, but each success brings a complication: the System itself seems to adjust its expectations. She learns from Theo that Cassel's investigation is backed by a higher authority. At the midpoint, she believes she has convinced Cassel she is a glitch that corrected itself, but he reveals a sealed file—the System flagged her at age 14 and deliberately left the error. The whiff of death comes when Cassel threatens to revoke Theo's class unless Maret submits to a full examination, forcing her to choose between her secret and her friend.",
      "emotionalArc": "confidence crumbling through escalating failures, leading to despair and resolve",
      "turningPoint": "Cassel threatens to strip Theo's adventurer class if Maret does not undergo a Revelation Rite that will expose her true stats."
    },
    {
      "number": 3,
      "name": "The True Number",
      "summary": "In the Revelation Rite, Maret faces the Arbiter and the System itself. She reveals that her stats are not a mistake—the System has been lying because her true class is not 'Scribe' but 'Anomaly,' a rare class meant to test the System's integrity. The climax forces Maret to choose: fight Cassel to protect her freedom, or trust him with the truth. She chooses to reveal everything, and the System recognizes her as a validator, granting her the authority to correct discrepancies. Cassel, impressed by her integrity, agrees to work with her.",
      "emotionalArc": "desperation rising to a decisive confrontation, ending in cautiously hopeful resolution",
      "turningPoint": "Maret chooses to reveal her true class and stats, which the System validates, transforming her from a fugitive into an authorized anomaly hunter."
    }
  ],
  "centralConflict": "Maret wants to keep her false stats hidden to maintain her freedom and safety, but Arbiter Cassel is determined to expose and correct the anomaly.",
  "theme": "Is the truth always liberating, or can a lie protect something the System cannot understand?",
  "endingDirection": "bittersweet empowerment"
}

{
  "characters": [
    {
      "id": "char_maret",
      "name": "Maret",
      "role": "protagonist",
      "backstory": "At fourteen, Maret received her System evaluation like every other child in Veridell. Her Strength read 3. But when she casually bent a steel ladle at dinner that same week, she knew something was wrong. Terrified of being dissected by Arbiters, she chose the Scribe class—officially non-combat, but with administrative access that let her avoid physical tests. For eight years, she's hidden her true capabilities behind paperwork and evasion, never daring to level a combat class. She has no idea why the System falsified her stats, but she fears the answer may be worse than the lie.",
      "traits": [
        "Hides her strength behind meticulous avoidance of physical confrontation",
        "Over-analyzes every interaction for threats to her secret",
        "Uses her scribe access to monitor official records for any mention of anomalies",
        "Trusts no one fully, but values those who don't push for answers",
        "Speaks in hedges and qualifiers to avoid committing to a statement"
      ],
      "speechPattern": "Prefers passive voice ('The ledger shows...', 'It has been noted that...'). Uses formal grammar and avoids slang. Frequently inserts 'per the System record' or 'according to available data' as a shield. When nervous, becomes excessively verbose and technical, burying the point in qualifications. Rarely says 'I' directly—uses 'one' or 'this scribe.' Avoids answering direct questions about her capabilities with irrelevant details or requests for clarification.",
      "internalConflict": "She wants to know why the System lied about her stats, but she needs to remain unnoticed to stay safe. Every step toward the truth risks exposure.",
      "avoids": "She refuses to use physical force in public, even to help someone, because demonstrating strength would contradict her records. She also avoids direct emotional declarations, expressing concern only through action or impersonal statements.",
      "goals": "To uncover the reason behind her false stats without alerting the Arbiters.",
      "fears": "Being publicly exposed as an anomaly and taken by the Divine Concord for study, her life reduced to a case file.",
